                                    <div className="text-right">
                                        <div className="font-bold dark:text-gray-200">#{order.id}</div>
                                        <div className="text-gray-500">{order.date}</div>
                                    </div>
                                </div>
                            )) : (
                                <p className="text-center text-gray-400 text-sm">لا توجد طلبات لهذا المستخدم</p>
                            )}
